interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // Parse provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Build request body
    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    // Handle size
    if (size) {
      requestBody.size = size;
    } else if (pixelArtOptions?.size) {
      requestBody.size = pixelArtOptions.size;
    }

    // Handle aspect ratio (not natively supported, emit warning)
    if (aspectRatio) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the size parameter instead.',
      });
    }

    // Handle seed
    if (seed != null) {
      requestBody.seed = seed;
    }

    // Handle provider-specific options
    if (pixelArtOptions?.style) {
      requestBody.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelArtOptions.pixelDensity;
    }

    // Handle unsupported features
    if (options.files != null && options.files.length > 0) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'files',
        details: 'PixelArt does not support image editing.',
      });
    }

    if (options.mask != null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'mask',
        details: 'PixelArt does not support inpainting.',
      });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(image => image.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: value.data.map(image => ({
            style: image.style ?? null,
            pixelDensity: image.pixel_density ?? null,
          })),
        },
      },
    };
  }
}

// Response schemas
const pixelArtImageDataSchema = z.object({
  b64_json: z.string(),
  style: z.string().nullish(),
  pixel_density: z.number().nullish(),
});

const pixelArtImageResponseSchema = z.object({
  data: z.array(pixelArtImageDataSchema),
});

// Error handling
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

